func (s *Session) initialize(ctx context.Context) error {
	commands := []struct {
		method string
		params map[string]any
	}{
		{method: "Page.enable"},
		{method: "Runtime.enable"},
		{method: "Network.enable"},
		{method: "Emulation.setDeviceMetricsOverride", params: map[string]any{
			"width":             s.width,
			"height":            s.height,
			"deviceScaleFactor": 1,
			"mobile":            false,
		}},
		{method: "Runtime.addBinding", params: map[string]any{"name": bindingName}},
		{method: "Page.addScriptToEvaluateOnNewDocument", params: map[string]any{
			"source": domCaptureScript(),
		}},
		{method: "Runtime.evaluate", params: map[string]any{
			"expression":            domCaptureScript(),
			"includeCommandLineAPI": false,
		}},
	}
	for _, command := range commands {
		if _, err := s.send(ctx, command.method, command.params); err != nil {
			return fmt.Errorf("%s: %w", command.method, err)
		}
	}
	return nil
}

func (s *Session) IsClosed() bool {
	s.mu.Lock()
	defer s.mu.Unlock()
	return s.closed
}

func (s *Session) Close() error {
	s.mu.Lock()
	if s.closed {
		s.mu.Unlock()
		return nil
	}
	s.closed = true
	pending := s.pending
	s.pending = make(map[int]chan cdpResponse)
	s.mu.Unlock()

	for _, ch := range pending {
		close(ch)
	}

	var err error
	if s.conn != nil {
		err = errors.Join(err, s.conn.Close(websocket.StatusNormalClosure, "browser session closed"))
	}
	if s.process != nil && s.process.Process != nil {
		_ = s.process.Process.Kill()
		_, waitErr := s.process.Process.Wait()
		err = errors.Join(err, waitErr)
	}
	if s.userDataDir != "" {
		err = errors.Join(err, os.RemoveAll(s.userDataDir))
	}
	return err
}

