func (s *Session) Key(ctx context.Context, input KeyInput) error {
	key := input.Key
	if key == "" {
		return errors.New("key is required")
	}
	modifiers := keyModifiers(input)
	text := input.Text
	if text == "" && len(key) == 1 && !input.CtrlKey && !input.MetaKey && !input.AltKey {
		text = key
	}
	params := map[string]any{
		"type":      "keyDown",
		"key":       key,
		"code":      input.Code,
		"modifiers": modifiers,
	}
	if text != "" {
		params["text"] = text
		params["unmodifiedText"] = text
	}
	if _, err := s.send(ctx, "Input.dispatchKeyEvent", params); err != nil {
		return err
	}
	_, err := s.send(ctx, "Input.dispatchKeyEvent", map[string]any{
		"type":      "keyUp",
		"key":       key,
		"code":      input.Code,
		"modifiers": modifiers,
	})
	return err
}

func (s *Session) Snapshot(ctx context.Context) (Snapshot, error) {
	history, err := s.navigationHistory(ctx)
	if err != nil {
		return Snapshot{}, err
	}
	title, _ := s.documentTitle(ctx)
	screenshot, err := s.captureScreenshot(ctx)
	if err != nil {
		return Snapshot{}, err
	}

	s.mu.Lock()
	width := s.width
	height := s.height
	events := append([]DOMEvent(nil), s.events...)
	if history.URL != "" {
		s.lastURL = history.URL
	}
	if title != "" {
		s.lastTitle = title
	}
	url := firstNonEmpty(history.URL, s.lastURL)
	if title == "" {
		title = s.lastTitle
	}
	s.mu.Unlock()

	return Snapshot{
		CanGoBack:    history.CanGoBack,
		CanGoForward: history.CanGoForward,
		DOMEvents:    events,
		Height:       height,
		Screenshot:   "data:image/png;base64," + screenshot,
		Title:        title,
		URL:          url,
		Width:        width,
	}, nil
}

