		Payload: map[string]any{"id": sessionID},
	}
}

// NewSessionUpdated builds a TypeSessionUpdated event for sessionID.
func NewSessionUpdated(sessionID string) Event {
	return Event{
		Type:    TypeSessionUpdated,
		Payload: map[string]any{"id": sessionID},
	}
}

